"use client";

import { useState } from "react";
import { ArenaToggle } from "@/components/ArenaToggle";
import { ChessMode } from "./ChessMode";
import { FootballMode } from "./FootballMode";
import { motion } from "framer-motion";

export const Arena = () => {
    const [mode, setMode] = useState<"chess" | "football">("chess");

    return (
        <section className="min-h-screen w-full flex flex-col items-center justify-center pt-24 px-4">
            <motion.div
                initial={{ opacity: 0, y: -20 }}
                animate={{ opacity: 1, y: 0 }}
                className="mb-12"
            >
                <ArenaToggle mode={mode} setMode={setMode} />
            </motion.div>

            <motion.div
                key={mode}
                initial={{ opacity: 0, x: mode === "chess" ? -20 : 20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: mode === "chess" ? 20 : -20 }}
                transition={{ duration: 0.5 }}
                className="w-full"
            >
                {mode === "chess" ? <ChessMode /> : <FootballMode />}
            </motion.div>
        </section>
    );
};
