"use client";

import { useState, useRef, useEffect, Suspense, useMemo } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Canvas, useFrame } from "@react-three/fiber";
import { PerspectiveCamera, Environment } from "@react-three/drei";
import * as THREE from "three";
import { Model as FootballModel } from "@/components/FootballModel";
import cvData from "@/data/cv_data.json";

// Bezier curve animation hook
const useBezierAnimation = (
    start: THREE.Vector3,
    end: THREE.Vector3,
    isAnimating: boolean,
    onComplete: () => void
) => {
    const curve = useMemo(() => {
        // Create an arc for the kick
        const midPoint = new THREE.Vector3().addVectors(start, end).multiplyScalar(0.5);
        midPoint.y += 2; // arc height
        return new THREE.QuadraticBezierCurve3(start, midPoint, end);
    }, [start, end]);

    const ballPos = useRef(new THREE.Vector3().copy(start));
    const progress = useRef(0);

    useFrame((state, delta) => {
        if (!isAnimating) {
            progress.current = 0;
            ballPos.current.copy(start);
            return;
        }

        if (progress.current < 1) {
            progress.current += delta * 1.5; // Animation speed
            if (progress.current > 1) {
                progress.current = 1;
                onComplete();
            }
            curve.getPoint(progress.current, ballPos.current);
        }
    });

    return ballPos;
};

const PenaltyScene = ({ 
    onShoot, 
    outcome, 
    target, 
    setTarget 
}: { 
    onShoot: (outcome: "goal" | "save") => void, 
    outcome: "none" | "goal" | "save",
    target: THREE.Vector3 | null,
    setTarget: (t: THREE.Vector3) => void
}) => {
    const ballStart = new THREE.Vector3(0, 0.2, 5);
    const [isAnimating, setIsAnimating] = useState(false);
    
    const gkRef = useRef<THREE.Mesh>(null);
    const ballRef = useRef<THREE.Group>(null);

    // If target is set but not animating, start it
    useEffect(() => {
        if (target && !isAnimating && outcome === "none") {
            // Determine outcome randomly or based on some logic
            const isGoal = Math.random() > 0.4; // 60% chance to score
            onShoot(isGoal ? "goal" : "save");
            setIsAnimating(true);
            
            // Audio cue
            const audio = new Audio('data:audio/wav;base64,UklGRiQAAABXQVZFZm10IBAAAAABAAEARKwAAIhYAQACABAAZGF0YQAAAAA='); // Silent fallback
            audio.play().catch(() => {});
        }
    }, [target, isAnimating, outcome, onShoot]);

    const ballPos = useBezierAnimation(
        ballStart, 
        target || ballStart, 
        isAnimating, 
        () => {
            setIsAnimating(false);
        }
    );

    useFrame((state, delta) => {
        if (ballRef.current) {
            ballRef.current.position.copy(ballPos.current);
            // Spin ball
            if (isAnimating) {
                ballRef.current.rotation.x -= delta * 10;
            }
        }

        // Goalkeeper AI
        if (gkRef.current && target && isAnimating) {
            const gkTargetX = outcome === "save" ? target.x : (target.x > 0 ? -1 : 1);
            gkRef.current.position.x = THREE.MathUtils.lerp(gkRef.current.position.x, gkTargetX, delta * 5);
            
            // Dive motion
            if (outcome === "save" && ballPos.current.z < 0) {
                 gkRef.current.position.y = THREE.MathUtils.lerp(gkRef.current.position.y, target.y - 0.5, delta * 5);
            }
        } else if (gkRef.current && !isAnimating) {
            // Return to center
            gkRef.current.position.x = THREE.MathUtils.lerp(gkRef.current.position.x, 0, delta * 2);
            gkRef.current.position.y = THREE.MathUtils.lerp(gkRef.current.position.y, 1, delta * 2);
        }
    });

    const handleTargetClick = (e: any) => {
        if (outcome !== "none" || isAnimating) return;
        setTarget(e.point);
    };

    return (
        <group>
            {/* Minimalist Goal Frame */}
            <mesh position={[0, 1.5, -5]}>
                <boxGeometry args={[6, 3, 0.2]} />
                <meshStandardMaterial color="#ffffff" />
            </mesh>
            <mesh position={[0, 1.5, -5.2]}>
                 <boxGeometry args={[5.8, 2.8, 0.2]} />
                 <meshStandardMaterial color="#000000" />
            </mesh>

            {/* Invisible Hitboxes */}
            <mesh position={[0, 1.5, -4.9]} onClick={handleTargetClick} visible={false}>
                <planeGeometry args={[5.8, 2.8]} />
            </mesh>

            {/* Goalkeeper (Monolithic Silhouette) */}
            <mesh ref={gkRef} position={[0, 1, -4.5]} castShadow>
                <boxGeometry args={[0.8, 2, 0.4]} />
                <meshStandardMaterial color="#111111" roughness={0.8} />
            </mesh>

            {/* The Ball */}
            <group ref={ballRef} scale={0.5}>
                <FootballModel />
            </group>

            {/* Ground */}
            <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, 0, 0]} receiveShadow>
                <planeGeometry args={[50, 50]} />
                <meshStandardMaterial color="#0a0a0a" />
            </mesh>
        </group>
    );
};

export const FootballMode = () => {
    const [outcome, setOutcome] = useState<"none" | "goal" | "save">("none");
    const [target, setTarget] = useState<THREE.Vector3 | null>(null);
    const [goalData, setGoalData] = useState<any>(null);
    const [saveData, setSaveData] = useState<any>(null);

    useEffect(() => {
        const firstPrize = cvData.achievements.find(a => a.rank.includes("1st") && a.name.includes("Football")) || cvData.achievements[0];
        const secondPrize = cvData.achievements.find(a => a.rank.includes("2nd") && a.name.includes("Football")) || cvData.achievements[1];
        
        setGoalData(firstPrize);
        setSaveData(secondPrize);
    }, []);

    const reset = () => {
        setOutcome("none");
        setTarget(null);
    };

    return (
        <div className="flex flex-col items-center justify-center p-8 w-full h-[600px] max-w-4xl mx-auto relative group">
            <h2 className="text-3xl font-serif text-white mb-4 z-10 drop-shadow-lg pointer-events-none">The Striker</h2>
            <p className="text-neutral-400 mb-8 z-10 pointer-events-none">Click inside the goal frame to take the shot.</p>

            <div className="absolute inset-0 w-full h-full bg-black rounded-lg border border-white/10 overflow-hidden shadow-[0_0_50px_rgba(0,0,0,1)]">
                <Canvas shadows dpr={[1, Math.min(window.devicePixelRatio, 2)]}>
                    <Suspense fallback={null}>
                        <PerspectiveCamera makeDefault position={[0, 2, 8]} fov={50} />
                        <ambientLight intensity={0.5} />
                        <directionalLight position={[0, 10, 5]} intensity={1} castShadow />
                        
                        <PenaltyScene 
                            onShoot={setOutcome} 
                            outcome={outcome} 
                            target={target}
                            setTarget={setTarget}
                        />

                        <Environment preset="night" />
                    </Suspense>
                </Canvas>
            </div>

            <AnimatePresence>
                {outcome !== "none" && (
                    <motion.div
                        initial={{ opacity: 0, scale: 0.8 }}
                        animate={{ opacity: 1, scale: 1 }}
                        className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-black/80 backdrop-blur-md rounded-lg p-6 text-center"
                    >
                        {outcome === "goal" ? (
                            <>
                                <h3 className="text-5xl font-serif text-green-400 mb-4 tracking-wider uppercase">Goal</h3>
                                <p className="text-white text-2xl font-bold mb-2">{goalData?.name}</p>
                                <p className="text-neutral-300 text-lg">Rank: {goalData?.rank}</p>
                                <p className="text-neutral-400 text-sm mt-4 font-mono max-w-md">"{goalData?.context}"</p>
                            </>
                        ) : (
                            <>
                                <h3 className="text-5xl font-serif text-red-500 mb-4 tracking-wider uppercase">Saved</h3>
                                <p className="text-white text-2xl font-bold mb-2">{saveData?.name}</p>
                                <p className="text-neutral-300 text-lg">Rank: {saveData?.rank}</p>
                                <p className="text-neutral-400 text-sm mt-4 font-mono max-w-md">"{saveData?.context}"</p>
                                <p className="text-neutral-500 text-xs mt-2 italic">Resilience proven.</p>
                            </>
                        )}
                        <button
                            onClick={reset}
                            className="mt-8 px-8 py-3 bg-white/10 hover:bg-white/20 rounded-full text-white transition-colors"
                        >
                            Shoot Again
                        </button>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
};
