"use client";

import { useState, useRef, useEffect, Suspense } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Canvas, useFrame, useThree } from "@react-three/fiber";
import { PerspectiveCamera, Environment } from "@react-three/drei";
import { useDrag } from "@use-gesture/react";
import * as THREE from "three";
import { Model as ChessBoardModel } from "@/components/ChessBoardModel";
import cvData from "@/data/cv_data.json";

const TARGET_POSITION = new THREE.Vector3(1, 0, -1);
const START_POSITION = new THREE.Vector3(2, 0, 2);

const DraggablePiece = ({ onSnap }: { onSnap: () => void }) => {
    const [isSnapped, setIsSnapped] = useState(false);
    const [isDragging, setIsDragging] = useState(false);
    const meshRef = useRef<THREE.Mesh>(null);
    const targetPos = useRef(new THREE.Vector3().copy(START_POSITION));
    const currentPos = useRef(new THREE.Vector3().copy(START_POSITION));
    const { size } = useThree();

    const bind = useDrag(({ active, movement: [x, y] }) => {
        if (isSnapped) return;
        setIsDragging(active);

        if (active) {
            const factor = 15 / size.width;
            targetPos.current.set(
                START_POSITION.x + x * factor,
                0.5,
                START_POSITION.z + y * factor
            );
        } else {
            const dist = currentPos.current.distanceTo(TARGET_POSITION);
            if (dist < 1.5) {
                setIsSnapped(true);
                targetPos.current.copy(TARGET_POSITION);
                onSnap();
                
                const audio = new Audio('data:audio/wav;base64,UklGRiQAAABXQVZFZm10IBAAAAABAAEARKwAAIhYAQACABAAZGF0YQAAAAA=');
                audio.play().catch(() => {});
            } else {
                targetPos.current.copy(START_POSITION);
            }
        }
    });

    useFrame((state, delta) => {
        if (meshRef.current) {
            // Smoothly interpolate current position towards target
            currentPos.current.lerp(targetPos.current, delta * 15);
            meshRef.current.position.copy(currentPos.current);
            
            // Subtle hover animation when dragging
            if (isDragging) {
                meshRef.current.rotation.y += delta * 2;
                meshRef.current.position.y += Math.sin(state.clock.elapsedTime * 10) * 0.05;
            }
        }
    });

    return (
        <mesh 
            // @ts-ignore
            {...bind()}
            ref={meshRef}
            castShadow
            receiveShadow
        >
            <cylinderGeometry args={[0.3, 0.4, 1.2, 32]} />
            <meshPhysicalMaterial 
                color={isSnapped ? "#10b981" : "#e2e8f0"} 
                roughness={0.1} 
                transmission={isSnapped ? 0 : 0.9} 
                thickness={1} 
                envMapIntensity={2} 
            />
        </mesh>
    );
};

export const ChessMode = () => {
    const [revealed, setRevealed] = useState(false);
    const [achievement, setAchievement] = useState<any>(null);

    useEffect(() => {
        const brilliant = cvData.achievements.find(a => a.name.includes("Mumbai Hacks"));
        setAchievement(brilliant || cvData.achievements[0]);
    }, []);

    return (
        <div className="flex flex-col items-center justify-center p-8 w-full h-[600px] max-w-4xl mx-auto relative group">
            <h2 className="text-3xl font-serif text-white mb-4 z-10 drop-shadow-lg pointer-events-none">The Brilliant Move</h2>
            <p className="text-neutral-400 mb-8 z-10 pointer-events-none">Drag the glowing piece to the target square (e6).</p>

            <div className="absolute inset-0 w-full h-full bg-black rounded-lg border border-white/10 overflow-hidden shadow-[0_0_50px_rgba(0,0,0,1)]">
                <Canvas 
                    shadows 
                    frameloop="demand"
                    dpr={[1, 2]}
                >
                    <Suspense fallback={null}>
                        <PerspectiveCamera makeDefault position={[0, 8, 8]} fov={45} />
                        <ambientLight intensity={0.2} />
                        <spotLight 
                            position={[5, 10, 5]} 
                            angle={0.15} 
                            penumbra={1} 
                            intensity={2} 
                            castShadow 
                            shadow-bias={-0.0001}
                        />
                        
                        {!revealed && (
                            <mesh position={[TARGET_POSITION.x, 0.01, TARGET_POSITION.z]} rotation={[-Math.PI / 2, 0, 0]}>
                                <planeGeometry args={[1, 1]} />
                                <meshBasicMaterial color="#10b981" transparent opacity={0.3} />
                            </mesh>
                        )}

                        <group scale={1} position={[0, -0.5, 0]}>
                            <ChessBoardModel />
                            <DraggablePiece onSnap={() => setRevealed(true)} />
                        </group>

                        <Environment preset="city" />
                    </Suspense>
                </Canvas>
            </div>

            <AnimatePresence>
                {revealed && achievement && (
                    <motion.div
                        initial={{ opacity: 0, scale: 0.8 }}
                        animate={{ opacity: 1, scale: 1 }}
                        className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-black/80 backdrop-blur-md rounded-lg p-6 text-center"
                    >
                        <h3 className="text-4xl font-serif text-green-400 mb-2">Victory!</h3>
                        <p className="text-white text-xl mb-4 font-semibold">
                            {achievement.name}
                        </p>
                        <div className="text-md text-neutral-300 font-mono mb-2">
                            Rank: {achievement.rank}
                        </div>
                        <div className="text-sm text-neutral-500 font-mono max-w-md">
                            "{achievement.context}"
                        </div>
                        <button
                            onClick={() => window.location.reload()}
                            className="mt-8 px-6 py-2 bg-white/10 hover:bg-white/20 rounded-full text-white transition-colors text-sm"
                        >
                            Reset Arena
                        </button>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
};
